// ── FILE ATTACHMENT COMPONENT ─────────────────────────────────────────────────
function Attachments({attachments=[], onChange}) {
  const fileRef = useRef();
  const addFiles = async (files) => {
    const newAtts = [];
    for(const f of files) {
      const b64 = await fileToB64(f);
      newAtts.push({id:`att_${Date.now()}_${Math.random()}`,name:f.name,type:f.type,size:f.size,data:b64,added:nowDate()});
    }
    onChange([...attachments, ...newAtts]);
  };
  const remove = id => onChange(attachments.filter(a=>a.id!==id));
  const isImg = a => a.type?.startsWith("image/");

  return (
    <div>
      <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:8}}>
        {attachments.map(a=>(
          <div key={a.id} style={{position:"relative",borderRadius:8,overflow:"hidden",border:`1px solid ${T.border}`,background:T.surface}}>
            {isImg(a) ? (
              <img src={a.data} alt={a.name} style={{width:80,height:80,objectFit:"cover",display:"block"}}/>
            ) : (
              <div style={{width:80,height:80,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:4}}>
                <div style={{fontSize:22}}>📄</div>
                <div style={{fontSize:9,color:T.muted,textAlign:"center",marginTop:2,wordBreak:"break-all"}}>{a.name.slice(0,16)}</div>
              </div>
            )}
            <button onClick={()=>remove(a.id)} style={{position:"absolute",top:2,right:2,width:18,height:18,borderRadius:9,background:"rgba(0,0,0,.7)",color:"#fff",fontSize:10,display:"flex",alignItems:"center",justifyContent:"center",padding:0}}>×</button>
          </div>
        ))}
        <button onClick={()=>fileRef.current.click()} style={{width:80,height:80,borderRadius:8,border:`2px dashed ${T.border}`,background:T.surface,color:T.muted,fontSize:11,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4}}>
          <span style={{fontSize:20}}>+</span>
          <span>Add File</span>
        </button>
      </div>
      <input ref={fileRef} type="file" multiple accept="image/*,.pdf,.doc,.docx,.xls,.xlsx" style={{display:"none"}}
        onChange={e=>{addFiles(Array.from(e.target.files));e.target.value="";}}/>
    </div>
  );
}

// ── AI FUEL RECEIPT SCANNER ───────────────────────────────────────────────────
function FuelReceiptScanner({onDataExtracted}) {
  const [scanning, setScanning] = useState(false);
  const [error, setError] = useState("");
  const fileRef = useRef();

  const scanReceipt = async (file) => {
    setScanning(true); setError("");
    try {
      const b64 = await fileToB64(file);
      const base64Data = b64.split(",")[1];
      const mediaType = file.type || "image/jpeg";

      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body: JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:1000,
          messages:[{
            role:"user",
            content:[
              {type:"image",source:{type:"base64",media_type:mediaType,data:base64Data}},
              {type:"text",text:`You are a fuel receipt data extractor for a trucking bookkeeping app. Extract all data from this fuel receipt image and return ONLY a JSON object with these fields (use null for missing fields):
{
  "date": "YYYY-MM-DD or null",
  "stationName": "string or null",
  "stationAddress": "string or null",
  "stationCity": "string or null",
  "stationState": "2-letter state code or null",
  "fuelTypes": [
    {
      "type": "Diesel|DEF|Reefer Fuel|CNG|Propane|Other",
      "gallons": number or null,
      "pricePerGallon": number or null,
      "total": number or null
    }
  ],
  "taxPaid": true or false,
  "totalAmount": number or null,
  "paymentMethod": "string or null",
  "receiptNumber": "string or null",
  "unitNumber": "string or null",
  "notes": "any other relevant info or null"
}
Return ONLY the JSON, no other text.`}
            ]
          }]
        })
      });
      const data = await response.json();
      const text = data.content?.map(c=>c.text||"").join("") || "";
      const clean = text.replace(/```json|```/g,"").trim();
      const parsed = JSON.parse(clean);
      onDataExtracted(parsed, b64);
    } catch(err) {
      setError("Could not read receipt. Please fill in manually.");
    } finally { setScanning(false); }
  };

  return (
    <div>
      <div style={{background:`${T.accent}15`,border:`1px solid ${T.accent}40`,borderRadius:8,padding:"10px 14px",marginBottom:12}}>
        <div style={{fontSize:12,fontWeight:700,color:T.accent,marginBottom:4}}>Smart Receipt Scan</div>
        <div style={{fontSize:11,color:T.muted,marginBottom:8}}>Photo a receipt to auto-fill date, station, gallons, and price. Required IFTA fields will be highlighted.</div>
        <Btn onClick={()=>fileRef.current.click()} disabled={scanning} variant="ghost" style={{fontSize:12,padding:"6px 14px",width:"100%"}}>
          {scanning ? "Scanning receipt..." : "Scan Receipt Photo"}
        </Btn>
        {error && <div style={{fontSize:11,color:T.red,marginTop:6}}>{error}</div>}
      </div>
      <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}}
        onChange={e=>{if(e.target.files[0])scanReceipt(e.target.files[0]);e.target.value="";}}/>
    </div>
  );
}

