function FuelEntryForm({entry, onChange, profile}) {
  const up = (f,v) => onChange({...entry,[f]:v});
  const upLine = (ft,f,v) => {
    const line = {...entry.fuelLines[ft],[f]:v};
    // auto-calc total
    if(f==="gallons"||f==="ppg") {
      const g=Number(f==="gallons"?v:line.gallons)||0;
      const p=Number(f==="ppg"?v:line.ppg)||0;
      if(g&&p) line.total=(g*p).toFixed(2);
    }
    if(f==="total"&&line.gallons) {
      const g=Number(line.gallons)||0;
      if(g) line.ppg=(Number(v)/g).toFixed(4);
    }
    onChange({...entry,fuelLines:{...entry.fuelLines,[ft]:line}});
  };

  const autoFillFromScan = (data, imgB64) => {
    const updates = {
      date: data.date||entry.date,
      stationName: data.stationName||entry.stationName,
      stationAddress: data.stationAddress||entry.stationAddress,
      stationCity: data.stationCity||entry.stationCity,
      stationState: data.stationState||entry.stationState,
      receiptNumber: data.receiptNumber||entry.receiptNumber,
      taxPaid: data.taxPaid||false,
      totalAmount: data.totalAmount||entry.totalAmount,
      paymentMethod: data.paymentMethod||entry.paymentMethod,
      notes: data.notes||entry.notes,
      fuelLines: {...entry.fuelLines},
    };
    if(data.fuelTypes?.length) {
      for(const ft of data.fuelTypes) {
        const key = FUEL_TYPES.find(k=>k.toLowerCase()===ft.type?.toLowerCase()) || "Diesel";
        updates.fuelLines[key] = {on:true,gallons:ft.gallons||"",ppg:ft.pricePerGallon||"",total:ft.total||""};
      }
    }
    if(imgB64) updates.attachments=[...entry.attachments,{id:`att_${Date.now()}`,name:"receipt_scan.jpg",type:"image/jpeg",data:imgB64,added:nowDate()}];
    onChange(updates);
  };

  // IFTA validation
  const isMissingIfta = !entry.date||!entry.stationName||!entry.stationAddress||!entry.taxPaid;
  const anyFuelOn = FUEL_TYPES.some(ft=>entry.fuelLines[ft]?.on);
  const grandTotal = FUEL_TYPES.reduce((s,ft)=>s+(entry.fuelLines[ft]?.on?(Number(entry.fuelLines[ft]?.total)||0):0),0);

  return (
    <div>
      <FuelReceiptScanner onDataExtracted={autoFillFromScan}/>

      {isMissingIfta && anyFuelOn && (
        <div style={{background:`${T.yellow}15`,border:`1px solid ${T.yellow}50`,borderRadius:8,padding:"8px 12px",marginBottom:12}}>
          <div style={{fontSize:11,fontWeight:700,color:T.yellow}}>IFTA Compliance — Required Fields Missing</div>
          <div style={{fontSize:11,color:T.muted,marginTop:3}}>
            {!entry.date&&"• Date of purchase  "}
            {!entry.stationName&&"• Station name  "}
            {!entry.stationAddress&&"• Station address  "}
            {!entry.taxPaid&&"• Tax paid confirmation"}
          </div>
        </div>
      )}

      <Card style={{marginBottom:12}}>
        <SecHdr title="Station & Purchase Info"/>
        <Row2>
          <Field label="Date *"><input type="date" value={entry.date} onChange={e=>up("date",e.target.value)}/></Field>
          <Field label="Receipt #"><input value={entry.receiptNumber} onChange={e=>up("receiptNumber",e.target.value)}/></Field>
        </Row2>
        <Field label="Station Name *"><input value={entry.stationName} onChange={e=>up("stationName",e.target.value)} placeholder="Pilot Travel Center"/></Field>
        <Field label="Station Address *"><input value={entry.stationAddress} onChange={e=>up("stationAddress",e.target.value)} placeholder="123 Main St"/></Field>
        <Row2>
          <Field label="City"><input value={entry.stationCity} onChange={e=>up("stationCity",e.target.value)}/></Field>
          <Field label="State"><select value={entry.stationState} onChange={e=>up("stationState",e.target.value)}>{STATES.map(s=><option key={s}>{s}</option>)}</select></Field>
        </Row2>
        <Row2>
          <Field label="Assign to Unit *">
            <select value={entry.unitId} onChange={e=>up("unitId",e.target.value)}>
              <option value="">Select unit</option>
              {profile.units.map(u=><option key={u.id} value={u.id}>{u.identifier||u.make||u.id}</option>)}
            </select>
          </Field>
          <Field label="Fleet">
            <select value={entry.fleetId} onChange={e=>up("fleetId",e.target.value)}>
              {profile.fleets.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}
            </select>
          </Field>
        </Row2>
        <div className="toggle-row">
          <div>
            <div style={{fontSize:13,fontWeight:600,color:T.text}}>Tax Paid on Receipt *</div>
            <div style={{fontSize:11,color:T.muted}}>Required for IFTA tax-paid credit</div>
          </div>
          <Toggle value={entry.taxPaid} onChange={v=>up("taxPaid",v)}/>
        </div>
        <Field label="Payment Method" style={{marginTop:12}}>
          <select value={entry.paymentMethod} onChange={e=>up("paymentMethod",e.target.value)}>
            {["","Cash","Credit Card","Fuel Card","Fleet Card","EFS","Comcheck"].map(m=><option key={m}>{m}</option>)}
          </select>
        </Field>
      </Card>

      <Card style={{marginBottom:12}}>
        <SecHdr title="Fuel Types Purchased"/>
        {FUEL_TYPES.map(ft=>(
          <div key={ft}>
            <div className="toggle-row">
              <span style={{fontSize:13,fontWeight:600,color:T.text}}>{ft}</span>
              <Toggle value={entry.fuelLines[ft]?.on||false} onChange={v=>upLine(ft,"on",v)}/>
            </div>
            {entry.fuelLines[ft]?.on && (
              <div style={{background:T.surface,borderRadius:8,padding:"10px 12px",margin:"6px 0 10px"}}>
                <Row2 cols="1fr 1fr 1fr" gap={8}>
                  <Field label="Gallons *"><input type="number" step="0.001" value={entry.fuelLines[ft].gallons} onChange={e=>upLine(ft,"gallons",e.target.value)} placeholder="0.000"/></Field>
                  <Field label="Price/Gal *"><input type="number" step="0.001" value={entry.fuelLines[ft].ppg} onChange={e=>upLine(ft,"ppg",e.target.value)} placeholder="0.000"/></Field>
                  <Field label="Total *">
                    <input type="number" step="0.01" value={entry.fuelLines[ft].total} onChange={e=>upLine(ft,"total",e.target.value)} placeholder="0.00"
                      style={{borderColor: !entry.fuelLines[ft].total ? T.red : T.border}}/>
                  </Field>
                </Row2>
              </div>
            )}
          </div>
        ))}
        {grandTotal>0 && (
          <div style={{borderTop:`1px solid ${T.border}`,marginTop:8,paddingTop:10,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{fontSize:13,fontWeight:700,color:T.muted}}>Grand Total</span>
            <span style={{fontSize:18,fontWeight:800,color:T.green}}>{fmt$(grandTotal)}</span>
          </div>
        )}
      </Card>

      <Card style={{marginBottom:12}}>
        <SecHdr title="Attachments"/>
        <Attachments attachments={entry.attachments} onChange={v=>up("attachments",v)}/>
      </Card>

      <Field label="Notes">
        <textarea value={entry.notes} onChange={e=>up("notes",e.target.value)} rows={2} placeholder="Notes..." style={{resize:"vertical"}}/>
      </Field>
    </div>
  );
}

// ── PROFILE TAB ───────────────────────────────────────────────────────────────
